import math
from sympy import prime
def ulam_coords(n):
    if n == 1:
        return (0, 0)
    k = math.ceil((math.sqrt(n) - 1) / 2)
    t = 2 * k
    m = (t + 1) ** 2
    if n >= m - t:
        return (k - (m - n), -k)
    m -= t
    if n >= m - t:
        return (-k, -k + (m - n))
    m -= t
    if n >= m - t:
        return (-k + (m - n), k)
    m -= t
    return (k, k - (m - n))
def seq(num):
    sequence = []
    for n in range(1, num + 1):
        p1 = prime(n)
        p2 = prime(n + 1)
        x1, y1 = ulam_coords(p1)
        x2, y2 = ulam_coords(p2)
        dist = max(abs(x1 - x2), abs(y1 - y2))
        sequence.append(dist)
    return sequence
print(seq(50))

